import React,{ useState } from 'react';
import styled from 'styled-components';

const Container = styled.div`
    width: 350px;
    min-height: 100px;
    padding: 10px;
    margin: 5px;
    display: ${(props => props.visible === true ? 'flex' : 'none')};
    flex-direction: column;
    align-items: center;
    justify-content: center;
    position: fixed;
    top: 140px;
    right: 5px;
    z-index: 100;
    background-color: black;
    color: white;
`
const Holder = styled.ul`
    width: 100%;
`

const Item = styled.ul`
    width: 100%;
    margin-bottom: 10px;
    padding: 10px;
    border-bottom: 1px solid grey;
    display: flex;
    align-items: center;
    justify-content: space-between;
    position: relative; 
`

const Remove = styled.div`
    width: 15px;
    height: 15px;
    display: flex;
    align-items: center;
    justify-content: center;
    position: absolute;
    top: 0px;
    right: 0px;
    border-radius: 5px;
    background-color: rgba(236, 55, 55, 0.658);
    cursor: pointer;
    &:hover{
        background-color: white;
        color: rgba(236, 55, 55, 0.658);
    }
`

const ItemImage = styled.img`
    width: 50px;
    height: auto;
`

const ItemLabel = styled.div`
    margin: 10px;
`

const Price = styled.div`
    font-size: 18px;
    font-weight: 600;
`

const Controls = styled.div`
    display: flex;
    align-items: center;
    padding: 5px;
`

const Button = styled.button`
    width: 20px;
    height: 20px;
    margin: 10px;
    cursor: pointer;
    &:hover{
        background-color: rgb(216, 216, 216);
    }
`

const Amount = styled.div`

`

const Total = styled.div`
    width: 100%;
    font-size: 18px;
    padding: 10px;
    margin-bottom: 10px;
`

const Value = styled.span`
    font-size: 20px;
`

const Checkout = styled.button`
    font-size: 18px;
    padding: 5px;
    color: darkcyan;
    border: 1px solid darkcyan;
    outline: none;
    border-radius: 5px;
    cursor: pointer;
    &:hover{
        background-color: rgb(189, 189, 189);
    }
`

export const Cart = () => {
    const [visibility, setVisibility] = useState(true);
    return (
        <Container visible={visibility} className='cart'>
            <Holder>
                <Item>
                    <Remove>x</Remove>
                    <ItemImage src='data:image/jpeg;base64,'/>
                    <ItemLabel>
                        HP Laptop  dew wfqj  
                    </ItemLabel>
                    <Price>$20</Price>
                    <Controls>
                        <Button className='remove'>-</Button>
                        <Amount>1</Amount>
                        <Button className='add'>+</Button>
                    </Controls>
                </Item>
            </Holder>
            <Total>TOTAL: $ <Value>25</Value></Total>
            <Checkout>CHECKOUT</Checkout>
        </Container>
    )
}
